public void init()
{
    super();

    Args args = element.args();
    ETGGrainReceiptNoteTable header;

    if (args && args.record() &&
    args.record().TableId == tableNum(ETGGrainReceiptNoteTable))
    {
        header = args.record();

        PurchTable purchTable = PurchTable::find(header.PurchId, true);

        if (purchTable)
        {
            ttsbegin;

            delete_from ETGGrainReceiptCharges
            where ETGGrainReceiptCharges.GrainReceiptNoteId == header.GrainReceiptNoteId;

            Map chargeMap = new Map(Types::String, Types::Real);

            MarkupTrans markupTrans;
            PurchLine purchLine;
            boolean headerChargesExist = false;

            select firstonly RecId from markupTrans
            where markupTrans.TransTableId == tableNum(PurchTable)
               && markupTrans.TransRecId  == purchTable.RecId;

            headerChargesExist = markupTrans.RecId != 0;

            if (headerChargesExist)
            {
                AmountCur totalLineAmount = 0.00;

                // Calculate total PO amount
                while select purchLine
                where purchLine.PurchId == purchTable.PurchId
                {
                    totalLineAmount += purchLine.LineAmount;
                }

                while select markupTrans
                where markupTrans.TransTableId == tableNum(PurchTable)
                   && markupTrans.TransRecId  == purchTable.RecId
                {
                    real amount;

                    if (markupTrans.MarkupCategory == MarkupCategory::Percent)
                    {
                        amount = (totalLineAmount * markupTrans.Value) / 100;
                    }
                    else
                    {
                        amount = markupTrans.Value;
                    }

                    if (chargeMap.exists(markupTrans.MarkupCode))
                    amount += chargeMap.lookup(markupTrans.MarkupCode);

                    chargeMap.insert(markupTrans.MarkupCode, amount);
                }
            }
            else
            {
                while select purchLine
                where purchLine.PurchId == purchTable.PurchId
                {
                    while select markupTrans
                    where markupTrans.TransTableId == tableNum(PurchLine)
                       && markupTrans.TransRecId  == purchLine.RecId
                    {
                        real amount;

                        amount = ETGLevyChargeSetup::calculateChargeFromMarkup(purchLine, markupTrans);

                        if (chargeMap.exists(markupTrans.MarkupCode))
                        amount += chargeMap.lookup(markupTrans.MarkupCode);

                        chargeMap.insert(markupTrans.MarkupCode, amount);
                    }
                }
            }

            MapEnumerator me = chargeMap.getEnumerator();

            while (me.moveNext())
            {
                ETGGrainReceiptCharges grnCharge;
                MarkupTable markupTable;

                str markupCode = me.currentKey();
                real amount = me.currentValue();

                grnCharge.clear();
                grnCharge.initValue();

                grnCharge.GrainReceiptNoteId = header.GrainReceiptNoteId;
                grnCharge.LineNumber         = this.getNextLineNum(header.GrainReceiptNoteId);
                grnCharge.ChargeMarkupCode   = markupCode;
                grnCharge.Amount             = amount;

                select firstonly markupTable
                where markupTable.MarkupCode == markupCode;

                if (markupTable)
                grnCharge.Description = markupTable.Txt;

                grnCharge.insert();
            }

            ttscommit;

            header.recalcNetAmountPayable();
        }

        ETGGrainReceiptCharges_ds.executeQuery();
    }
}

public void closeOk()
{
    super();

    ETGGrainReceiptNoteTable header;

    Args args = element.args();

    if (args && args.record())
    {
        header = args.record();

        header = ETGGrainReceiptNoteTable::
            findFromGrainReceiptNote(header.GrainReceiptNoteId, true);

        if (header)
        {
            header.recalcNetAmountPayable();
        }
    }
}

private int getNextLineNum(ETGGrainReceiptNoteId _grnId)
{
    ETGGrainReceiptCharges charge;
    int maxLineNum = 0;

    select maxof(LineNumber) from charge
    where charge.GrainReceiptNoteId == _grnId;

    maxLineNum = charge.LineNumber;

    return maxLineNum + 1;
}
